CREATE VIEW "BH".creches AS
 SELECT creche.id_equip_educacao AS id,
    creche.nome AS creche,
    creche.logradouro AS "LOGRADOURO",
    bairro."NOME" AS bairro,
    setor."ID_SETOR_CENSITARIO_2022",
    creche.geom
   FROM "BH".creches_conveniadas creche,
    "BH"."Bairro Oficial" bairro,
    "BH".setor_censitario setor
  WHERE (public.st_contains(bairro.geom, creche.geom) AND public.st_contains(setor.geom, creche.geom))
  ORDER BY creche.nome;


